helpers_tpl.template:

{{/*
Expand the name of the chart.
*/}}
{{- define "abc-bank.name" -}}
{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Create a default fully qualified app name.
*/}}
{{- define "abc-bank.fullname" -}}
{{- if .Values.fullnameOverride }}
{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- $name := default .Chart.Name .Values.nameOverride }}
{{- if contains $name .Release.Name }}
{{- .Release.Name | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- printf "%s-%s" .Release.Name $name | trunc 63 | trimSuffix "-" }}
{{- end }}
{{- end }}
{{- end }}

{{/*
Create chart name and version as used by the chart label.
*/}}
{{- define "abc-bank.chart" -}}
{{- printf "%s-%s" .Chart.Name .Chart.Version | replace "+" "_" | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Common labels
*/}}
{{- define "abc-bank.labels" -}}
helm.sh/chart: {{ include "abc-bank.chart" . }}
{{ include "abc-bank.selectorLabels" . }}
{{- if .Chart.AppVersion }}
app.kubernetes.io/version: {{ .Chart.AppVersion | quote }}
{{- end }}
app.kubernetes.io/managed-by: {{ .Release.Service }}
{{- end }}

{{/*
Selector labels
*/}}
{{- define "abc-bank.selectorLabels" -}}
app.kubernetes.io/name: {{ include "abc-bank.name" . }}
app.kubernetes.io/instance: {{ .Release.Name }}
{{- end }}

{{/*
Create the name of the service account to use
*/}}
{{- define "abc-bank.serviceAccountName" -}}
{{- if .Values.serviceAccount.create }}
{{- default (include "abc-bank.fullname" .) .Values.serviceAccount.name }}
{{- else }}
{{- default "default" .Values.serviceAccount.name }}
{{- end }}
{{- end }}

{{/*
PostgreSQL service name
*/}}
{{- define "abc-bank.postgresql.fullname" -}}
{{- printf "%s-postgres" (include "abc-bank.fullname" .) }}
{{- end }}

{{/*
Database connection URL
*/}}
{{- define "abc-bank.database.url" -}}
{{- printf "jdbc:postgresql://%s:%d/%s" (include "abc-bank.postgresql.fullname" .) (.Values.postgresql.service.port | int) .Values.database.name }}
{{- end }}

secrets_yaml.template:

apiVersion: v1
kind: Secret
metadata:
  name: {{ include "abc-bank.fullname" . }}-db-secret
  labels:
    {{- include "abc-bank.labels" . | nindent 4 }}
    app.kubernetes.io/component: database
type: Opaque
stringData:
  database-name: {{ .Values.database.name | quote }}
  database-user: {{ .Values.database.username | quote }}
  database-password: {{ .Values.database.password | quote }}

postgres_service_yaml.template:

{{- if .Values.postgresql.enabled }}
apiVersion: v1
kind: Service
metadata:
  name: {{ include "abc-bank.postgresql.fullname" . }}
  labels:
    {{- include "abc-bank.labels" . | nindent 4 }}
    app.kubernetes.io/component: database
spec:
  type: {{ .Values.postgresql.service.type }}
  ports:
  - port: {{ .Values.postgresql.service.port }}
    targetPort: postgresql
    protocol: TCP
    name: postgresql
  selector:
    {{- include "abc-bank.selectorLabels" . | nindent 4 }}
    app.kubernetes.io/component: database
{{- end }}

app_deployment_yaml.template:

apiVersion: apps/v1
kind: Deployment
metadata:
  name: {{ include "abc-bank.fullname" . }}
  labels:
    {{- include "abc-bank.labels" . | nindent 4 }}
    app.kubernetes.io/component: backend
spec:
  replicas: {{ .Values.app.replicaCount }}
  selector:
    matchLabels:
      {{- include "abc-bank.selectorLabels" . | nindent 6 }}
      app.kubernetes.io/component: backend
  template:
    metadata:
      annotations:
        checksum/secret: {{ include (print $.Template.BasePath "/secrets.yaml") . | sha256sum }}
        {{- with .Values.podAnnotations }}
        {{- toYaml . | nindent 8 }}
        {{- end }}
      labels:
        {{- include "abc-bank.selectorLabels" . | nindent 8 }}
        app.kubernetes.io/component: backend
    spec:
      {{- with .Values.podSecurityContext }}
      securityContext:
        {{- toYaml . | nindent 8 }}
      {{- end }}
      serviceAccountName: {{ include "abc-bank.serviceAccountName" . }}
      containers:
      - name: {{ .Chart.Name }}
        {{- with .Values.securityContext }}
        securityContext:
          {{- toYaml . | nindent 10 }}
        {{- end }}
        image: "{{ .Values.app.image.repository }}:{{ .Values.app.image.tag }}"
        imagePullPolicy: {{ .Values.app.image.pullPolicy }}
        ports:
        - name: http
          containerPort: {{ .Values.app.service.targetPort }}
          protocol: TCP
        env:
        # Database connection
        - name: SPRING_DATASOURCE_URL
          value: {{ include "abc-bank.database.url" . | quote }}
        - name: SPRING_DATASOURCE_USERNAME
          valueFrom:
            secretKeyRef:
              name: {{ include "abc-bank.fullname" . }}-db-secret
              key: database-user
        - name: SPRING_DATASOURCE_PASSWORD
          valueFrom:
            secretKeyRef:
              name: {{ include "abc-bank.fullname" . }}-db-secret
              key: database-password

        # JPA/Hibernate configuration
        - name: SPRING_JPA_HIBERNATE_DDL_AUTO
          value: "update"
        - name: SPRING_JPA_SHOW_SQL
          value: "false"
        - name: SPRING_SQL_INIT_MODE
          value: "always"

        # Application configuration
        - name: SPRING_PROFILES_ACTIVE
          value: {{ .Values.app.env.springProfile | quote }}
        - name: JAVA_OPTS
          value: {{ .Values.app.env.javaOpts | quote }}
        - name: LOGGING_LEVEL_COM_ABCBANK
          value: {{ .Values.app.env.logLevel | quote }}

        # Server configuration
        - name: SERVER_PORT
          value: {{ .Values.app.service.targetPort | quote }}

        resources:
          {{- toYaml .Values.app.resources | nindent 10 }}

        {{- with .Values.app.livenessProbe }}
        livenessProbe:
          {{- toYaml . | nindent 10 }}
        {{- end }}

        {{- with .Values.app.readinessProbe }}
        readinessProbe:
          {{- toYaml . | nindent 10 }}
        {{- end }}

      {{- with .Values.nodeSelector }}
      nodeSelector:
        {{- toYaml . | nindent 8 }}
      {{- end }}

      {{- with .Values.affinity }}
      affinity:
        {{- toYaml . | nindent 8 }}
      {{- end }}

      {{- with .Values.tolerations }}
      tolerations:
        {{- toYaml . | nindent 8 }}
      {{- end }}

route_yaml.template:

{{- if .Values.route.enabled }}
apiVersion: route.openshift.io/v1
kind: Route
metadata:
  name: {{ include "abc-bank.fullname" . }}
  labels:
    {{- include "abc-bank.labels" . | nindent 4 }}
spec:
  {{- if .Values.route.host }}
  host: {{ .Values.route.host }}
  {{- end }}
  path: {{ .Values.route.path }}
  to:
    kind: Service
    name: {{ include "abc-bank.fullname" . }}
    weight: 100
  port:
    targetPort: http
  {{- if .Values.route.tls.enabled }}
  tls:
    termination: {{ .Values.route.tls.termination }}
    insecureEdgeTerminationPolicy: {{ .Values.route.tls.insecureEdgeTerminationPolicy }}
  {{- end }}
  wildcardPolicy: None
{{- end }}

notes_txt.template:

Thank you for installing {{ .Chart.Name }}!

Your release is named {{ .Release.Name }}.

To learn more about the release, try:

  $ helm status {{ .Release.Name }}
  $ helm get all {{ .Release.Name }}

1. Get the application URL:

{{- if .Values.route.enabled }}
  export ROUTE_HOST=$(oc get route {{ include "abc-bank.fullname" . }} -o jsonpath='{.spec.host}')
  echo "Application URL: https://$ROUTE_HOST"
{{- else }}
  export POD_NAME=$(kubectl get pods --namespace {{ .Release.Namespace }} -l "app.kubernetes.io/name={{ include "abc-bank.name" . }},app.kubernetes.io/instance={{ .Release.Name }}" -o jsonpath="{.items[0].metadata.name}")
  echo "Visit http://127.0.0.1:8080 to use your application"
  kubectl --namespace {{ .Release.Namespace }} port-forward $POD_NAME 8080:8080
{{- end }}

2. Demo Credentials:
   Username: john.doe
   Password: password

3. Check application health:
   curl https://$ROUTE_HOST/actuator/health

4. View application logs:
   kubectl logs -f deployment/{{ include "abc-bank.fullname" . }}

5. View PostgreSQL logs:
   kubectl logs -f deployment/{{ include "abc-bank.postgresql.fullname" . }}

IMPORTANT NOTES:
- PostgreSQL uses emptyDir storage - data will be lost on pod restart
- This is a demo deployment - not suitable for production
- Change database password in values.yaml for production use
